    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'okki_api_dump_' + ts + '.json';
    a.click();
    document.getElementById('__okki_status').innerHTML = '<span style="color:#ffab40;">已导出 ' + captured.length + ' 个请求</span>';
  };
  document.getElementById('__okki_clear').onclick = function() { captured.length = 0; seen.clear(); document.getElementById('__okki_list').innerHTML = '<div style="color:#555;">已清空</div>'; };
  document.getElementById('__okki_close').onclick = function() { document.getElementById('__okki_intercept_panel').remove(); };

  console.log('%cOKKI API Monitor v2 已激活 %c| 右下角面板', 'color:#4fc3f7;font-weight:bold;', 'color:#999;');
})();
```

**操作顺序**：
1. 先离开"全部客户"页面 → 点左侧菜单去"首页"
2. 粘贴这段代码，回车 → 右下角出现面板
3. 点回到"全部客户"
4. 看面板

只捕获到 1 个聊天 API，客户列表接口没触发。SPA 应用可能用了缓存。换 Performance API 方式，从浏览器底层抓网络请求：

```javascript
(function() {
  'use strict';
  if (document.getElementById('__okki_intercept_panel')) document.getElementById('__okki_intercept_panel').remove();

  const panel = document.createElement('div');
  panel.id = '__okki_intercept_panel';
  panel.innerHTML = '<div style="position:fixed; bottom:20px; right:20px; z-index:999999; background:#1a1a2e; color:#e0e0e0; border-radius:12px; padding:16px; font:12px/1.5 Consolas,Monaco,monospace; box-shadow:0 8px 32px rgba(0,0,0,0.5); width:440px; border:1px solid #333;"><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;"><span style="font-size:14px;font-weight:700;color:#4fc3f7;">OKKI API Monitor v3 (Performance)</span><span id="__s" style="font-size:11px;color:#66bb6a;">● 监听中</span></div><div id="__c" style="margin-bottom:8px;font-size:11px;color:#999;">已捕获: 0 个请求</div><div id="__l" style="max-height:300px;overflow-y:auto;margin-bottom:10px;font-size:10px;color:#aaa;word-break:break-all;"><div style="color:#555;">先点"清空"，再刷新页面</div></div><div style="display:flex;gap:8px;"><button id="__e" style="flex:1;padding:8px;background:#4fc3f7;color:#000;border:none;border-radius:6px;cursor:pointer;font-weight:700;">导出JSON</button><button id="__x" style="flex:1;padding:8px;background:#333;color:#ccc;border:none;border-radius:6px;cursor:pointer;">清空</button><button id="__z" style="padding:8px 12px;background:#444;color:#999;border:none;border-radius:6px;cursor:pointer;">X</button></div></div>';
  document.body.appendChild(panel);

  const captured = [];
  let counter = 0;

  function add(url) {
    if (captured.find(c => c.url === url)) return;
    counter++;
    captured.push({ url });
    const l = document.getElementById('__l');
    if (l.querySelector('div[style]')) l.innerHTML = '';
    const el = document.createElement('div');
    el.style.cssText = 'padding:3px 0;border-bottom:1px solid #222;';
    el.textContent = url.substring(0, 120);
    l.insertBefore(el, l.firstChild);
    while (l.children.length > 50) l.removeChild(l.lastChild);
    document.getElementById('__c').innerHTML = '已捕获: ' + counter + ' 个请求';
  }

  // Method 1: PerformanceObserver - captures ALL network entries
  try {
    const po = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (entry.name && entry.name.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff|ttf|ico)/i.test(entry.name)) {
          add(entry.name);
        }
      }
    });
    po.observe({ type: 'resource', buffered: true });
  } catch(e) { console.log('PO err:', e.message); }

  // Method 2: fetch + XHR intercept as backup
  const of = window.fetch;
  window.fetch = function(...a) {
    const u = typeof a[0] === 'string' ? a[0] : a[0]?.url || '';
    if (u.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff|ttf|ico)/i.test(u)) add(u);
    return of.apply(this, a);
  };
  const O = XMLHttpRequest.prototype.open, S = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(m,u,...r) { this.__u=u; return O.apply(this,[m,u,...r]); };
  XMLHttpRequest.prototype.send = function(...a) {
    const x=this; if(x.__u && x.__u.includes('xiaoman.cn') && !/\.(jpg|png|avif|gif|svg|js|css|woff)/i.test(x.__u)) add(x.__u);
    return S.apply(this,a);
  };

  document.getElementById('__e').onclick = function() {
    const ts = new Date().toISOString().replace(/[:.]/g, '-');
    const blob = new Blob([JSON.stringify({ exportedAt: new Date().toISOString(), total: captured.length, urls: captured }, null, 2)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'okki_urls_' + ts + '.json'; a.click();
    document.getElementById('__s').innerHTML = '<span style="color:#ffab40;">已导出 ' + captured.length + ' 条</span>';
  };
  document.getElementById('__x').onclick = function() { captured.length = 0; counter = 0; document.getElementById('__l').innerHTML = '<div style="color:#555;">已清空 — 现在去刷新页面或切换页面</div>'; document.getElementById('__c').innerHTML = '已捕获: 0'; };
  document.getElementById('__z').onclick = function() { document.getElementById('__okki_intercept_panel').remove(); };

  console.log('%cOKKI Monitor v3 已激活 %c| 右下角 | 支持 PerformanceObserver+fetch+XHR', 'color:#4fc3f7;font-weight:bold;', 'color:#999;');
})();
```

**关键步骤**：粘贴这段代码到 Console 回车后，**点面板上的"清空"按钮**，然后**按 Ctrl+Shift+R 强制刷新**（不是普通刷新），这会跳过缓存重新加载所有数据。
